const auth = $('인증 확인').item.json.result;
const body = $('Webhook').item.json.body;

if (!auth.success) {
  return [{ json: { success: false, message: auth.message || '인증 실패' } }];
}

// 카테고리 업로드 권한 확인
const cats = auth.categories || [];
const targetCat = cats.find(c => c.table_name === body.category || c.name === body.category);

if (!targetCat) {
  return [{ json: { success: false, message: '접근 불가한 카테고리입니다' } }];
}

if (!targetCat.can_upload && !['super_admin','company_admin'].includes(auth.role)) {
  return [{ json: { success: false, message: '업로드 권한이 없습니다' } }];
}

return [{ json: {
  authorized: true,
  userId: auth.id,
  tableName: targetCat.table_name,
  filename: body.filename,
  filedata: body.filedata,
  filesize: body.filesize,
  mimetype: body.mimetype || 'application/octet-stream'
} }];

// Base64 → Binary 변환
const item = $input.first().json;
const binary = Buffer.from(item.filedata, 'base64');
return [{
  json: {
    tableName: item.tableName,
    filename: item.filename,
    userId: item.userId,
    mimetype: item.mimetype
  },
  binary: {
    data: {
      data: binary,
      mimeType: item.mimetype,
      fileName: item.filename
    }
  }
}];

// 파일 메타데이터 저장
const driveItem = $input.first();
const prevJson = $('Base64 → Binary').item.json;
return [{ json: {
  tableName: prevJson.tableName,
  filename: prevJson.filename,
  userId: prevJson.userId,
  driveFileId: driveItem.json.id,
  driveUrl: `https://drive.google.com/file/d/${driveItem.json.id}/view`
} }];

// GPT 응답에서 청크 파싱
const content = $input.first().json.choices[0].message.content;
const meta = $('Drive URL 저장').item.json;

let chunks = [];
try {
  // JSON 배열 파싱 시도
  const match = content.match(/\[\s*\{[\s\S]*\}\s*\]/);
  if (match) {
    const parsed = JSON.parse(match[0]);
    chunks = parsed.map(c => c.chunk || c.content || c.text || String(c));
  }
} catch (e) {
  // 파싱 실패시 전체를 하나의 청크로
  chunks = [content];
}

if (chunks.length === 0) chunks = [content];

// 각 청크를 임베딩 요청 형태로 변환
return chunks.map((chunk, i) => ({
  json: {
    chunk,
    chunkIndex: i,
    totalChunks: chunks.length,
    tableName: meta.tableName,
    filename: meta.filename,
    driveFileId: meta.driveFileId,
    driveUrl: meta.driveUrl,
    userId: meta.userId
  }
}));

// 모든 청크 완료 후 요약 반환
const items = $input.all();
return [{ json: {
  success: true,
  chunks: items.length,
  filename: $('청크 파싱').first().json.filename,
  message: `${items.length}개 청크가 저장되었습니다`
} }];
